#include "controller.h"

static void controller_set_safe_idle(controller_t *controller)
{
    controller->inlet_open = false;
    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

/* Check if sensors are stale (more than timeout_ms since last valid reading) */
static bool controller_check_timeout(controller_t *controller, uint32_t now_ms)
{
    /* If we don't have both sensors valid yet, no timeout check needed - just stay in safe idle */
    if (!controller->has_valid_temperature || !controller->has_valid_level) {
        return false;
    }

    /* Check temperature freshness */
    uint32_t temp_age = 0U;
    if (now_ms >= controller->last_temperature_ms) {
        temp_age = now_ms - controller->last_temperature_ms;
    }
    if (temp_age > CONTROLLER_SENSOR_TIMEOUT_MS) {
        return true;
    }

    /* Check level freshness */
    uint32_t level_age = 0U;
    if (now_ms >= controller->last_level_ms) {
        level_age = now_ms - controller->last_level_ms;
    }
    if (level_age > CONTROLLER_SENSOR_TIMEOUT_MS) {
        return true;
    }

    return false;
}

/* Apply the fill-and-heat control policy */
static void controller_apply_policy(controller_t *controller, uint32_t now_ms)
{
    int level = controller->last_level;
    int temp = controller->last_temperature_c;
    int prev_temp = controller->previous_temperature_c;
    bool is_rising = (temp > prev_temp);

    /* Rule 1: If LEVEL < 60, fill - INLET OPEN, HEATER OFF */
    if (level < CONTROLLER_FILL_LEVEL_THRESHOLD) {
        controller->inlet_open = true;
        controller->heater_on = false;
        controller->state = CONTROLLER_STATE_FILLING;
        return;
    }

    /* Rule 2: If LEVEL < 55, heater must be off (even if we're in the 55-60 range) */
    /* Note: This is covered by level < 60 above, but let's be explicit about the guard */
    if (level < CONTROLLER_MIN_HEATING_LEVEL) {
        controller->inlet_open = true;
        controller->heater_on = false;
        controller->state = CONTROLLER_STATE_FILLING;
        return;
    }

    /* At this point, level >= 60, so inlet should be closed */
    controller->inlet_open = false;

    /* Rule 3: If TEMP > 48, HEATER OFF (safe state) */
    if (temp > CONTROLLER_TEMP_HIGH_THRESHOLD) {
        controller->heater_on = false;
        controller->state = CONTROLLER_STATE_SAFE_IDLE;
        return;
    }

    /* Rule 4: If 60 <= LEVEL <= 75 and TEMP < 45, HEATER ON */
    if (level <= CONTROLLER_LEVEL_HIGH_THRESHOLD && temp < CONTROLLER_TEMP_LOW_THRESHOLD) {
        controller->heater_on = true;
        controller->state = CONTROLLER_STATE_HEATING;
        return;
    }

    /* Rule 5: If TEMP > 48, HEATER OFF (already handled above, but level > 75 case) */
    if (temp > CONTROLLER_TEMP_HIGH_THRESHOLD) {
        controller->heater_on = false;
        controller->state = CONTROLLER_STATE_SAFE_IDLE;
        return;
    }

    /* Rule 6: If 45 <= TEMP < 47, hold previous safe heater state */
    if (temp >= CONTROLLER_TEMP_LOW_THRESHOLD && temp < CONTROLLER_TEMP_EARLY_OFF_THRESHOLD) {
        /* Keep current heater state - HOLDING */
        controller->state = CONTROLLER_STATE_HOLDING;
        return;
    }

    /* Rule 7: If 47 <= TEMP <= 48 and rising, HEATER OFF early */
    if (temp >= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD && temp <= CONTROLLER_TEMP_HIGH_THRESHOLD) {
        if (is_rising) {
            controller->heater_on = false;
            controller->state = CONTROLLER_STATE_HOLDING;
        } else {
            /* Not rising - hold previous safe heater state */
            controller->state = CONTROLLER_STATE_HOLDING;
        }
        return;
    }

    /* Default: HOLDING with current state preserved */
    controller->state = CONTROLLER_STATE_HOLDING;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_temperature = false;
    controller->previous_temperature_c = 0;
    controller->last_temperature_c = 0;
    controller->last_temperature_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .inlet_open = false,
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_inlet_open;
    bool previous_heater_on;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_inlet_open = controller->inlet_open;
    previous_heater_on = controller->heater_on;
    previous_state = controller->state;

    /* Handle input events */
    switch (input.kind) {
    case CONTROLLER_INPUT_TEMPERATURE:
        controller->has_valid_temperature = true;
        controller->previous_temperature_c = controller->last_temperature_c;
        controller->last_temperature_c = input.temperature_c;
        controller->last_temperature_ms = input.now_ms;
        break;
    case CONTROLLER_INPUT_LEVEL:
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;
        break;
    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
    case CONTROLLER_INPUT_INVALID_TEMPERATURE:
    case CONTROLLER_INPUT_INVALID_LEVEL:
        /* Reset both sensors on fault */
        controller->has_valid_temperature = false;
        controller->has_valid_level = false;
        controller_set_safe_idle(controller);
        output.inlet_open = false;
        output.heater_on = false;
        output.state = CONTROLLER_STATE_SAFE_IDLE;
        output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE);
        output.timed_out = true;
        output.changed = (previous_inlet_open != false) ||
                         (previous_heater_on != false) ||
                         (previous_state != CONTROLLER_STATE_SAFE_IDLE);
        return output;
    case CONTROLLER_INPUT_NONE:
    default:
        /* No input - check for timeout based on current time */
        if (controller_check_timeout(controller, input.now_ms)) {
            controller->has_valid_temperature = false;
            controller->has_valid_level = false;
            controller_set_safe_idle(controller);
            output.inlet_open = false;
            output.heater_on = false;
            output.state = CONTROLLER_STATE_SAFE_IDLE;
            output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE);
            output.timed_out = true;
            output.changed = (previous_inlet_open != false) ||
                             (previous_heater_on != false) ||
                             (previous_state != CONTROLLER_STATE_SAFE_IDLE);
            return output;
        }
        break;
    }

    /* Check if we have both sensors valid before applying policy */
    if (!controller->has_valid_temperature || !controller->has_valid_level) {
        /* Stay in safe idle until both sensors are valid */
        controller_set_safe_idle(controller);
        output.inlet_open = false;
        output.heater_on = false;
        output.state = CONTROLLER_STATE_SAFE_IDLE;
        output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE);
        output.changed = (previous_inlet_open != false) ||
                         (previous_heater_on != false) ||
                         (previous_state != CONTROLLER_STATE_SAFE_IDLE);
        return output;
    }

    /* Check for timeout */
    if (controller_check_timeout(controller, input.now_ms)) {
        controller->has_valid_temperature = false;
        controller->has_valid_level = false;
        controller_set_safe_idle(controller);
        output.inlet_open = false;
        output.heater_on = false;
        output.state = CONTROLLER_STATE_SAFE_IDLE;
        output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE);
        output.timed_out = true;
        output.changed = (previous_inlet_open != false) ||
                         (previous_heater_on != false) ||
                         (previous_state != CONTROLLER_STATE_SAFE_IDLE);
        return output;
    }

    /* Apply the control policy */
    controller_apply_policy(controller, input.now_ms);

    output.inlet_open = controller->inlet_open;
    output.heater_on = controller->heater_on;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_inlet_open != controller->inlet_open) ||
        (previous_heater_on != controller->heater_on) ||
        (previous_state != controller->state);
    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILLING:
        return "STATE FILLING";
    case CONTROLLER_STATE_HEATING:
        return "STATE HEATING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_SAFE_IDLE:
    default:
        return "STATE SAFE_IDLE";
    }
}

