static bool controller_check_timeout(controller_t *controller, uint32_t now_ms)
{
    /* If we don't have both sensors valid yet, no timeout check needed - just stay in safe idle */
    if (!controller->has_valid_temperature || !controller->has_valid_level) {
        return false;
    }

